def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, -np.inf, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            continue
        ratio = item / capacity
        score = 0.0
        if ratio > 7:
            factor = 1.5
            for alpha in range(1, 6):
                power = 3 + 0.6 * alpha
                score -= 400 * (ratio - 7)**power
                score += 60 * np.cos(ratio * np.pi * alpha * 1.5)
            for beta in range(1, 8):
                score += np.exp(-0.9 * ratio * beta) * np.sin(beta * ratio * np.pi * 0.8) / (beta ** 1.2)
            for extra in range(5):
                score += np.log1p(ratio + extra) * np.cos(extra * ratio)
            if capacity % 11 == 0:
                score += 20 * np.sin(ratio * capacity * 0.8) - 10 * np.sqrt(abs(ratio - 1.1))
        elif 6 < ratio <= 7:
            score -= 135 * (ratio - 6)**4.2 + 80 * np.sin(ratio * 6)
            for gamma in range(1, 7):
                if gamma % 2 == 1:
                    score += np.tanh(ratio / (gamma + 0.7)) / (gamma ** 1.5)
                else:
                    score -= np.cosh(ratio * gamma / 1.7) / (gamma ** 2)
            score += np.exp(-0.5 * ratio) * np.sin(ratio * np.pi * 1.2) * 15
        elif 5 < ratio <= 6:
            score -= 110 * (ratio - 5)**3.9 + 65 * np.cos(ratio * 8)
            for delta in range(1, 9):
                if delta % 3 == 0:
                    score += np.log1p(ratio * delta) / (delta ** 1.1)
                else:
                    score -= np.exp(-ratio * delta) / (delta + 1.6)
            for epsilon in range(1, 5):
                score += ((-1) ** epsilon) * np.sin(ratio * np.pi * epsilon**1.2) / (epsilon**1.6)
        elif 4 < ratio <= 5:
            v = (ratio - 4) ** 3.0
            score -= 90 * v + 40 * np.sin(ratio * 10)
            for zeta in range(1, 7):
                if zeta % 2 == 1:
                    score += np.log1p(ratio * zeta) / (zeta + 1.5)
                else:
                    score -= np.exp(-ratio * zeta) / (zeta ** 1.4)
            score += np.sin(ratio * np.pi * 1.7) * np.tanh(v)
            for special in range(3):
                score += 12 * np.cos((special + 1) * ratio * 4) / (special + 1)
        elif 3 < ratio <= 4:
            vv = (ratio - 3) ** 2.9
            score -= 75 * vv + 38 * np.cos(ratio * 11)
            for eta in range(1, 8):
                if eta % 4 == 1:
                    score += np.log1p(ratio * eta) / (eta + 1.3)
                elif eta % 4 == 2:
                    score -= np.exp(-ratio * eta) / (eta ** 1.2)
                else:
                    score += np.sin(ratio * eta) / (eta + 0.7)
            score += np.sin(ratio * np.pi * 1.3) * np.tanh(vv)
        elif 2 < ratio <= 3:
            vvv = (ratio - 2) ** 2.7
            score -= 60 * vvv + 28 * np.cos(ratio * 12)
            for theta in range(1, 8):
                if theta % 5 == 2:
                    score -= np.exp(-ratio * theta) / (theta ** 1.3)
                else:
                    score += np.log1p(ratio * theta) / (theta + 1.0)
            score += np.sin(ratio * np.pi * 0.6) * np.tanh(vvv)
        elif 1 < ratio <= 2:
            score -= 50 * (ratio - 1)**2.5 + 22 * np.sin(ratio * 15)
            for phi in range(1, 7):
                if phi % 2 == 0:
                    score += ((-1)**phi) * np.cos(ratio * np.pi * phi**1.5) / (phi**2.0)
                else:
                    score -= ((-1)**phi) * np.sin(ratio * np.pi * phi**1.7) / (phi**1.7)
        else:
            step = 0.07
            added = False
            for k in range(1, 25):
                threshold = k * step
                if ratio < threshold:
                    score += (k ** 7) / (threshold - ratio + 1e-15)
                    added = True
                    break
            if not added:
                score += 16 * (1 - ratio)**3 + 10 * np.sin(ratio * 19)
            for i_f in range(1, 6):
                score += np.exp(-1.4 * i_f * ratio) * np.cos(i_f * ratio * np.pi * 1.7) / (i_f ** 1.1)
        penalty = 0.0
        for x in range(1, 15):
            term = ((-1) ** x) * (ratio ** (2.5 * x)) / (x * 5.0)
            if x % 7 == 0:
                penalty += term * np.log1p(x + 2 * ratio)
            elif x % 5 == 0:
                penalty += term / (1 + np.exp(-x*ratio/4))
            elif x % 3 == 0:
                penalty -= term * np.sin(x * ratio * 1.7)
            else:
                penalty += term * np.cos(ratio * x * 1.1)
        score += penalty
        if item > capacity:
            score -= 250
            for m in range(1, 11):
                if capacity == 0:
                    break
                mod_val = item % (capacity + m)
                score += (mod_val ** 0.9) / (m ** 0.8)
                if mod_val > capacity * 0.75:
                    score -= 40 / m
        elif (capacity - item) < 0.3 * capacity:
            score += 60
            for n in range(8):
                if capacity == 0:
                    break
                score += (capacity - item) * np.sin((n+1) * ratio * 3.5 * np.pi) / (n+1)
                if (capacity - item) < 0.12 * capacity:
                    score += 12 * np.cos((n+1) * ratio * 4.3)
        else:
            if ratio < 0.25:
                score -= 20 * np.exp(-ratio * 40) + 8 * np.sin(ratio * 38)
                for p in range(1, 10):
                    score += np.cos(ratio * np.pi * p * 1.5) / (p ** 3.5)
        if capacity % 17 == 0:
            score += 8 * (np.log1p(capacity) - ratio * 1.1) + np.cos(ratio * capacity * 1.5)
        elif capacity % 9 == 0:
            score -= 9 * np.sqrt(abs(ratio - 0.7)) + np.sin((capacity + ratio) * 6)
        else:
            for q in range(1, 15):
                if (capacity + q) % 6 == 0:
                    score += 1.3 * q / (1 + ratio * q) + 0.5 * np.cos(q * ratio * 1.5)
                else:
                    score -= 0.6 * np.sin(q * ratio * 1.6) / (q + 4)
        cap_int = int(capacity)
        if cap_int % 5 == 0 and ratio < 0.5:
            for r in range(1, 8):
                score += ((-1) ** r) * np.log1p(ratio * r * capacity * 1.7) / (r ** 1.2)
        elif cap_int % 6 == 2 and ratio < 0.48:
            for r in range(1, 7):
                score += ((-1) ** r) * np.log1p(ratio * r * capacity * 1.1) / r
        if ratio > 5 and capacity > 90:
            factor = 2.1
            for s in range(2, 8):
                score -= factor * np.exp((ratio - s)/s) / s
                if s % 3 == 0:
                    score += 3.0 * np.cos(s * ratio)
        if ratio == 0:
            score -= 1e10
        if score != score or not np.isfinite(score):
            score = -np.inf
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    max_p = np.max(finite_priorities)
    min_p = np.min(finite_priorities)
    if max_p == min_p:
        return np.where(np.isfinite(priorities), 1.0, -np.inf)
    normalized = (priorities - min_p) / (max_p - min_p)
    return np.where(np.isfinite(priorities), normalized, -np.inf)
